class Solution {
public:
    int findMaxK(vector<int>& nums) {
        unordered_set<int> numSet;
        int maxK = -1;
        for (int num : nums) {
            numSet.insert(num);
            if (numSet.find(-num) != numSet.end() && -num > 0) {
                maxK = max(maxK, abs(num));
            }
        }
        return maxK;
    }
};
